// // This module selects between two inputs based on the selection signal.
// When Sel is 0, Out is connected to B; when Sel is 1, Out is connected to A.
module mux_2to1 (
    input A,
    input B,
    input Sel,
    output Out,
    input VPB,
    input VPWR,
    input VGND,
    input VNB
);

assign Out = (!Sel & A) | (Sel & B);

endmodule
